use axum::extract::FromRequestParts;
use axum::http::request::Parts;
use axum::response::Redirect;
use tower_sessions::Session;
use uuid::Uuid;

use crate::domain::UserId;

/// Extractor that requires authentication.
/// If the user is not authenticated, redirects to /login.
pub struct AuthenticatedUser(pub UserId);

#[axum::async_trait]
impl<S> FromRequestParts<S> for AuthenticatedUser
where
    S: Send + Sync,
{
    type Rejection = Redirect;

    async fn from_request_parts(parts: &mut Parts, state: &S) -> Result<Self, Self::Rejection> {
        let session = Session::from_request_parts(parts, state)
            .await
            .map_err(|_| Redirect::to("/login"))?;

        let user_id: Option<String> = session
            .get("user_id")
            .await
            .map_err(|_| Redirect::to("/login"))?;

        match user_id {
            Some(id_str) => {
                let uuid = Uuid::parse_str(&id_str).map_err(|_| Redirect::to("/login"))?;
                Ok(AuthenticatedUser(UserId::from_uuid(uuid)))
            }
            None => Err(Redirect::to("/login")),
        }
    }
}

use sqlx::PgPool;
use uuid::Uuid;

use crate::domain::{PasswordHash_, UserId, ValidatedEmail};

pub struct UserRecord {
    pub id: Uuid,
    pub email: String,
    pub password_hash: String,
}

pub async fn insert_user(
    pool: &PgPool,
    id: &UserId,
    email: &ValidatedEmail,
    password_hash: &PasswordHash_,
) -> Result<(), sqlx::Error> {
    sqlx::query!(
        r#"INSERT INTO users (id, email, password_hash) VALUES ($1, $2, $3)"#,
        id.as_uuid(),
        email.as_str(),
        password_hash.as_str(),
    )
    .execute(pool)
    .await?;
    Ok(())
}

pub async fn find_user_by_email(
    pool: &PgPool,
    email: &str,
) -> Result<Option<UserRecord>, sqlx::Error> {
    let record = sqlx::query_as!(
        UserRecord,
        r#"SELECT id, email, password_hash FROM users WHERE email = $1"#,
        email,
    )
    .fetch_optional(pool)
    .await?;
    Ok(record)
}

